// Parse review output, merge with trigger input so state flows through
const raw = $input.first().json;
const triggerIn = $('When Executed by Parent').first().json;
let review;
try {
  const text = typeof raw.output === 'string' ? raw.output : JSON.stringify(raw.output);
  const m = text.match(/\{[\s\S]*\}/);
  review = JSON.parse(m ? m[0] : text);
  if (!review.scores || typeof review.overall !== 'number') throw new Error('Invalid scoring shape');
} catch(e) {
  review = {
    scores: { accuracy: 0, tone: 0, completeness: 0, clarity: 0 },
    overall: 0,
    issues: ['Reviewer output could not be parsed'],
    revisionNotes: 'The reviewer response was malformed. Treat this as a failed review and escalate or accept the draft as-is.',
    reviewParseError: e.message
  };
}

return {
  json: {
    ...triggerIn,
    review: review
  }
};
